Here's a complete example:

**XAML (e.g., `ItemsPage.xaml`)**

```xml
<ContentPage xmlns="http://schemas.microsoft.com/dotnet/2021/maui"
             xmlns:x="http://schemas.microsoft.com/winfx/2009/xaml"
             x:Class="MyApp.ItemsPage">

    <CollectionView ItemsSource="{Binding Items}"
                    SelectionMode="Single"
                    SelectedItem="{Binding SelectedItem}"
                    IsRefreshing="{Binding IsRefreshing}"
                    RemainingItemsThreshold="0">

        <!-- Pull-to-refresh wrapper -->
        <CollectionView.Behaviors>
            <!-- Or wrap in a RefreshView instead (see below) -->
        </CollectionView.Behaviors>

        <CollectionView.ItemTemplate>
            <DataTemplate>
                <Grid Padding="10" ColumnDefinitions="*,Auto">
                    <Label Text="{Binding Name}" FontSize="16" />
                    <Label Grid.Column="1" Text="{Binding Status}"
                           TextColor="Gray" />
                </Grid>
            </DataTemplate>
        </CollectionView.ItemTemplate>

        <CollectionView.EmptyView>
            <Label Text="No items found."
                   HorizontalOptions="Center"
                   VerticalOptions="Center" />
        </CollectionView.EmptyView>
    </CollectionView>

</ContentPage>
```

**Since `CollectionView` doesn't have built-in pull-to-refresh, wrap it in a `RefreshView`:**

```xml
<RefreshView Command="{Binding RefreshCommand}"
             IsRefreshing="{Binding IsRefreshing}">

    <CollectionView ItemsSource="{Binding Items}"
                    SelectionMode="Single"
                    SelectedItem="{Binding SelectedItem}">
        <!-- ItemTemplate as above -->
    </CollectionView>

</RefreshView>
```

**ViewModel (`ItemsViewModel.cs`)**

```csharp
public partial class ItemsViewModel : ObservableObject
{
    private readonly IApiService _api;
    private readonly INavigationService _nav;

    [ObservableProperty]
    private ObservableCollection<Item> _items = new();

    [ObservableProperty]
    private bool _isRefreshing;

    private Item? _selectedItem;
    public Item? SelectedItem
    {
        get => _selectedItem;
        set
        {
            if (SetProperty(ref _selectedItem, value) && value is not null)
            {
                // Navigate, then clear selection so user can re-select
                NavigateToDetail(value);
                SelectedItem = null;
            }
        }
    }

    [RelayCommand]
    private async Task Refresh()
    {
        try
        {
            var data = await _api.GetItemsAsync();
            Items = new ObservableCollection<Item>(data);
        }
        finally
        {
            IsRefreshing = false;   // stops the spinner
        }
    }

    private async void NavigateToDetail(Item item)
    {
        await Shell.Current.GoToAsync(
            nameof(DetailPage),
            new Dictionary<string, object> { ["Item"] = item });
    }
}
```

**Key binding relationships:**

| XAML Property | ViewModel Property | Purpose |
|---|---|---|
| `ItemsSource` | `Items` (ObservableCollection) | Drives the list |
| `SelectionMode="Single"` | — | Limits to one selection |
| `SelectedItem` | `SelectedItem` (two-way) | Triggers navigation on set |
| `RefreshView.Command` | `RefreshCommand` | Fires on pull-down gesture |
| `RefreshView.IsRefreshing` | `IsRefreshing` (two-way) | Controls the refresh spinner |

**Important details:**
- Set `IsRefreshing = false` in `finally` — otherwise the spinner never stops.
- Reset `SelectedItem` to `null` after navigating so the same row can be tapped again.
- `RefreshView` wraps `CollectionView` because `CollectionView` has no built-in refresh support.
